sql:
SELECT AVG(mass) AS average_mass
FROM meteorites
WHERE year = '1999-01-01';

SELECT name
FROM meteorites
WHERE year = '2020' AND mass > 1000;

SELECT m.name
FROM meteorites m
WHERE m.mass > (SELECT AVG(mass) FROM meteorites);

SELECT SUM(mass) AS total_mass
FROM meteorites
WHERE recclass = 'Pallasite' AND year = '2020';

SELECT COUNT(*) AS number_of_meteorites
FROM meteorites
WHERE recclass = 'Eucrite' AND discovery_method = 'Radar';

SELECT COUNT(*) AS total_eucrite_fell_meteorites
FROM meteorites
WHERE recclass = 'Eucrite' AND fall = 'Fell';

SELECT m.name
FROM meteorites m
WHERE m.recclass = 'Pallasite, ungrouped' AND m.research_status = 'Team 2';

SELECT DISTINCT year
FROM meteorites
ORDER BY year;

SELECT m.name, m.research_status, m.year
FROM meteorites m
WHERE m.mass > 1000 AND m.fall = 'Found';
